demos.desktop:
render(() => {
const [value, setValue] = React.useState({ one: false, two: false, three: false });
const [error, setError] = React.useState(false);

const onChange = (_, payload) => {
setValue({ ...value, [payload.name]: payload.checked });
};

return (
<div style={{ width: '100%' }}>
<CheckboxGroupDesktop
label='Планеты расположенные между Землёй и Солнцем'
direction='horizontal'
onChange={onChange}
hint='Выберите несколько планет'
error={error}
>
<Checkbox label='Меркурий' name='one' checked={value.one} size={24} />
<Checkbox label='Венера' name='two' checked={value.two} size={24} />
<Checkbox label='Нептун' name='three' checked={value.three} size={24} />
</CheckboxGroupDesktop>

<Gap size={32} />

<Space direction='horizontal' wrap={true}>
<Button size={32} onClick={() => setError(false)}>
По умолчанию
</Button>
<Button size={32} onClick={() => setError('Правильный ответ: Венера и Меркурий')}>
Состояние ошибки
</Button>
</Space>
</div>
);
});

